import json, os, sys

OUT = r"C:\Users\2121\AppData\Roaming\TRAE SOLO CN\ModularData\ai-agent\work-mode-projects\6a3ed37f1ac00f6e4879b1bd\chronos-app\src\data\narratives"

def A(id,title,key,scene,npcs,dlgs):
    return {"id":id,"title":title,"isKeyAct":key,"sceneDescription":scene,"npcDialogues":npcs,"dialogues":dlgs}

def D(id,text,spk,av,score,evt,note,cons):
    return {"id":id,"text":text,"speaker":spk,"avatar":av,"score":score,"triggeredEvent":evt,"historicalNote":note,"consequence":cons}

def N(spk,text,av):
    return {"speaker":spk,"text":text,"avatar":av}

def write_json(name, data):
    path = os.path.join(OUT, name)
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f"{name} written ({os.path.getsize(path)} bytes)")

# === modern-reform.json ===
write_json('modern-reform.json', {"eraId":"junior-modern-reform","eraName":"近代化探索","playerRole":"孙中山","acts":[
A("act-1","洋务运动",False,"19世纪60年代，面对内忧外患的困境，曾国藩、李鸿章等人发起了'师夷长技以制夷'的洋务运动。你孙中山此时还年轻，正在海外学习医学，但已经萌生了推翻清朝、振兴中华的革命思想。",[N("曾国藩","中国的病根不仅在制度，更在人心。我办洋务就是要用西方的技术来强国。","曾"),N("李鸿章","中堂大人说得对。我们造枪炮建工厂办学堂就是要让中国强大起来。","李")],[
D("d1","洋务运动走的是'中学为体西学为用'的路子。但我觉得光学技术还不够，必须改革制度才行。","我","孙",88,"孙中山评价洋务运动","洋务运动（1861-1895年）以'中学为体西学为用'为指导思想引进西方军事技术和工业设备。虽然创办了一批近代企业但由于不触及封建专制制度的根本最终未能实现富国强兵的目标。","孙中山开始思考革命的道路。"),
D("d2","李鸿章办了江南制造总局和福州船政局，还建立了北洋水师。投入不可谓不大，但甲午一战全废了。","我","孙",85,"洋务运动的成果与局限","洋务运动期间创办了约50个近代企业建立了北洋南洋福建三支海军。然而由于管理腐败技术依赖外国等原因这些成果在甲午战争中暴露出了致命弱点。","洋务运动的局限日益明显。"),
D("d3","我在海外看到了西方的民主制度，百姓有选举权有言论自由。这与清朝的专制形成了鲜明对比。","我","孙",90,"孙中山认识西方民主","孙中山在海外留学期间深入了解了西方的政治制度。他发现西方国家的繁荣与民主制度密切相关。这与他所熟悉的清朝专制体制形成了鲜明对比。","孙中山产生了革命的思想。"),
D("d4","曾国藩虽然维护清朝统治，但他的自律和学问值得敬佩。可惜他走错了方向。","我","孙",78,"孙中山评价曾国藩","曾国藩是洋务运动的发起人之一。他的个人品德和学识备受后人推崇但他选择维护清朝的专制统治使他站在了历史进步的对立面。","对曾国藩的评价因角度而异。"),
D("d5","中国的落后不仅是技术落后，更是思想落后。要救中国首先要唤醒国民的思想。","我","孙",86,"思想启蒙的重要性","孙中山认识到中国的落后是全方位的：技术落后、制度落后、思想落后。其中思想落后是最深层的落后。只有通过思想启蒙才能推动真正的社会进步。","思想启蒙是变革的基础。"),
D("d6","也许我一个人的力量太小了，但如果能团结更多的人一定能改变中国。","我","孙",80,"孙中山寻求革命伙伴","孙中山在早期革命活动中积极寻找志同道合的革命伙伴。他先后在檀香山香港日本等地建立了革命组织团结了一大批有志青年。","革命力量开始凝聚。")]),
A("act-2","戊戌变法",False,"1898年，光绪帝在康有为和梁启超的推动下发动了'戊戌变法'。你孙中山密切关注着这场变法，既抱有希望又充满担忧。",[N("康有为","皇上下诏变法废除八股兴办学堂训练新军奖励实业。这是中国走向富强的关键一步！","康"),N("梁启超","老师变法虽然好但阻力太大了。那些守旧大臣不会坐视不管的。","梁")],[
D("d1","康有为的上清帝书写得很好，变法的方向也正确。但我担心光绪帝没有足够的权力来推行这些改革。","我","孙",87,"孙中山评价戊戌变法","戊戌变法（1898年）是光绪帝在康有为梁启超等人推动下进行的一次政治改革。变法内容涵盖政治经济军事文化教育等多个方面。然而由于以慈禧太后为首的顽固派的强烈反对变法仅持续了103天就宣告失败。","变法的方向正确但时机不成熟。"),
D("d2","谭嗣同说'各国变法无不从流血而成'。他甘愿为变法流血，这份勇气令人敬佩！","我","孙",92,"谭嗣同的牺牲精神","戊戌变法失败后谭嗣同拒绝逃跑他说'各国变法无不从流血而成'。他最终被杀成为'戊戌六君子'之一。他的牺牲精神极大地鼓舞了革命派。","谭嗣同的牺牲激励了革命者。"),
D("d3","光绪帝虽然有心变法但手中没有实权。慈禧太后垂帘听政光绪帝不过是个傀儡。","我","孙",83,"光绪帝的困境","光绪帝虽然支持变法但实权掌握在慈禧太后手中。变法触动了许多守旧大臣的利益他们联合慈禧太后发动了政变软禁了光绪帝废除了所有变法令。","变法的失败有其必然性。"),
D("d4","康有为和梁启超的变法虽然失败了但他们唤醒了更多人的思想。变法的火种已经播下。","我","孙",85,"戊戌变法的历史意义","戊戌变法虽然失败了但它在中国近代史上产生了深远的影响。它推动了思想启蒙运动促进了新思想的传播为后来的辛亥革命做了思想准备。","变法的火种不会熄灭。"),
D("d5","戊戌变法证明了一件事：在专制体制下和平变法是行不通的。要改变中国必须用革命的手段。","我","孙",90,"从变法到革命的转变","戊戌变法的失败使越来越多的人认识到和平改良的道路在中国行不通。专制体制不会自动放弃权力必须通过革命手段推翻它。","革命成为唯一的出路。"),
D("d6","梁启超逃亡日本后继续用笔做武器传播变法和革命思想。他的文章影响了整整一代人。","我","孙",82,"梁启超的思想传播","梁启超逃亡日本后创办了《清议报》《新民丛报》等刊物继续宣传维新和革命思想。他的文章文笔犀利思想深刻对当时的知识界产生了巨大影响。","梁启超的笔力震撼人心。")]),
A("act-3","兴中会",False,"1894年你在檀香山创立了中国第一个资产阶级革命团体兴中会。誓词是'驱除鞑虏恢复中华创立合众政府'。虽然当时只有几十名会员但星星之火可以燎原。",[N("陈独秀","孙先生我在日本也听说了一些革命思想。虽然我们走的路不同但推翻清朝的目标是一致的。","陈"),N("梁启超","孙先生主张革命而我主张改良。我们虽然方法不同但都是为了救中国。","梁")],[
D("d1","'驱除鞑虏恢复中华创立合众政府。'这就是兴中会的宗旨！凡是有血性的中国人都应该加入我们！","我","孙",94,"孙中山创立兴中会","1894年11月孙中山在檀香山创立了兴中会这是中国第一个资产阶级革命团体。兴中会的誓词明确提出推翻清朝统治建立民主共和国的目标。虽然初期只有几十名会员但它标志着中国革命运动从自发走向了有组织的阶段。","兴中会点燃了革命的火种。"),
D("d2","第一次广州起义虽然失败了但革命的热情不会熄灭。失败是成功之母。","我","孙",85,"第一次广州起义","1895年兴中会策划了第一次广州起义但由于泄密而失败。陆皓东等革命党人被捕牺牲。这次起义虽然失败了但它标志着武装革命的开始。","革命之路充满荆棘。"),
D("d3","梁启超先生主张改良我主张革命。我们虽然方法不同但目标一致都是为了救中国。","我","孙",80,"革命与改良的分歧","孙中山与康有为梁启超等人就'革命'还是'改良'展开了激烈辩论。改良派认为应该通过和平变法来改革清朝革命派认为必须用武力推翻清朝。历史最终证明了革命派的观点是正确的。","革命与改良的分歧深刻影响了中国近代史。"),
D("d4","要革命成功必须团结更多的力量。海外华侨知识分子新军都是我们可以争取的对象。","我","孙",86,"孙中山扩大革命力量","孙中山在革命过程中非常重视力量的团结和整合。他积极联系海外华侨筹集革命经费争取国内知识分子和新军的支持。","革命力量不断壮大。"),
D("d5","陈独秀后来创办了《新青年》推动了新文化运动。虽然我们走的路不完全一样但他唤醒青年思想的贡献不可磨灭。","我","孙",78,"陈独秀与新文化运动","陈独秀于1915年创办《新青年》杂志发起了新文化运动高举'民主'和'科学'两面大旗。新文化运动为五四运动和马克思主义在中国的传播创造了条件。","新文化运动影响深远。"),
D("d6","革命不是一朝一夕的事需要长期的努力和准备。我们要有耐心也要有决心。","我","孙",82,"革命的长期性","孙中山的革命生涯充满了挫折和失败。从兴中会到同盟会从多次起义到辛亥革命成功他经历了十多年的艰苦奋斗。坚持不懈是革命成功的关键。","坚持不懈是革命成功的关键。")]),
A("act-4","同盟会成立",True,"1905年你在日本东京将兴中会华兴会光复会等革命团体合并为中国同盟会被推选为总理。同盟会的成立标志着中国革命运动进入了一个新的阶段。",[N("黄兴","孙先生各革命团体终于合并了。同盟会就是中国革命的总指挥部！","黄"),N("宋教仁","我们要制定一个完整的革命纲领让所有人都知道我们为什么要革命。","宋")],[
D("d1","同盟会的纲领是'驱除鞑虏恢复中华创立民国平均地权'。这十六个字就是我们革命的旗帜！","我","孙",96,"同盟会的革命纲领","1905年同盟会在东京成立孙中山被推选为总理。同盟会的政治纲领后来概括为'三民主义'。","同盟会成为革命的领导核心。"),
D("d2","'三民主义'——民族民权民生。这三个方面缺一不可是中国走向现代化的完整方案。","我","孙",93,"三民主义的提出","孙中山将同盟会的纲领概括为'三民主义'：民族主义（推翻清朝统治实现民族独立）、民权主义（建立民主共和制度保障人民权利）、民生主义（平均地权发展国民经济）。","三民主义成为革命的指导思想。"),
D("d3","创办《民报》作为同盟会的机关报用笔做武器传播革命思想。","我","孙",88,"民报与革命宣传","同盟会成立后创办了《民报》作为机关报大力宣传三民主义和革命思想。","《民报》成为革命的重要阵地。"),
D("d4","黄兴将军是革命的军事统帅宋教仁先生擅长组织和策划。有了你们的帮助我对革命更有信心。","我","孙",85,"革命团队的核心成员","同盟会汇聚了一批优秀的革命人才：黄兴是军事领袖多次亲临前线指挥战斗；宋教仁是组织天才擅长政治策划。","革命团队人才济济。"),
D("d5","同盟会成立后各地的革命活动空前活跃。南方的会党北方的新军海外的华侨都在积极响应。","我","孙",84,"同盟会的革命活动","同盟会成立后在全国范围内开展革命活动。从1907年到1911年同盟会发动了多次武装起义。","革命浪潮此起彼伏。"),
D("d6","革命的道路虽然艰难但方向是正确的。只要我们坚持到底就一定能成功！","我","孙",82,"孙中山对革命的信心","孙中山对革命的最终胜利始终充满信心。尽管经历了多次起义失败的打击他仍然坚信革命的方向是正确的。","信心是前进的动力。")]),
A("act-5","屡败屡战",False,"从1907年到1911年同盟会发动了多次武装起义。每一次都失败了但每一次都动摇了清朝的统治。",[N("黄兴","又失败了。但每一次起义都让我们积累了经验。下次一定能成功！","黄"),N("陈独秀","孙先生你们的起义虽然失败了但民众的思想已经被唤醒了。这是最大的收获。","陈")],[
D("d1","广州起义失败后七十二烈士英勇牺牲。他们的血没有白流！全国人民都被感动了！","我","孙",90,"黄花岗起义","1911年4月同盟会在广州发动黄花岗起义黄兴率领敢死队攻打两广总督署。起义失败后七十二位烈士的遗骸被安葬在黄花岗。","黄花岗起义震动全国。"),
D("d2","屡败屡战越挫越勇。失败一次就总结一次经验为下一次的胜利做准备。","我","孙",87,"屡败屡战的革命精神","从兴中会到同盟会孙中山领导的革命运动经历了十多次起义失败。但他始终坚持不放弃。这种屡败屡战的精神最终换来了辛亥革命的成功。","失败是成功之母。"),
D("d3","起义虽然失败了但在全国各地播下了革命的火种。新军中的革命思想越来越浓厚。","我","孙",83,"革命思想在新军中的传播","同盟会在清朝新军中积极开展宣传和组织工作。武昌的新军革命思想尤为浓厚为后来的武昌起义做好了准备。","新军中的革命暗流涌动。"),
D("d4","海外华侨是我们的坚强后盾。没有他们的经费支持革命不可能坚持这么久。","我","孙",85,"海外华侨的革命贡献","海外华侨为辛亥革命提供了大量的经费支持。据统计华侨为革命捐款总额超过百万港元。","华侨的贡献永载史册。"),
D("d5","每次起义失败后我们都要重新组织重新筹款重新计划。这需要巨大的毅力和耐心。","我","孙",80,"革命工作的艰难","革命工作极其艰难。每一次失败后都要从零开始重新准备。","革命者承受着巨大的压力。"),
D("d6","我知道辛亥革命的成功不会太远了。因为清朝已经从根子上烂透了。","我","孙",82,"预感到革命即将成功","1911年春夏清朝的统治已经摇摇欲坠。革命的条件已经基本成熟。","革命的曙光就在前方。")]),
A("act-6","武昌起义",False,"1911年10月10日武昌新军中的革命党人发动了起义。起义军迅速占领了武汉三镇各省纷纷响应。你孙中山此时正在美国筹款得知消息后立即启程回国。",[N("黄兴","武昌起义成功了！各省纷纷宣布独立！清朝的统治终于要结束了！","黄"),N("梁启超","没想到革命来得这么快！两千年帝制就要终结了？","梁")],[
D("d1","武昌起义成功了！各省纷纷响应宣布独立。两千年的封建帝制终于要终结了！","我","孙",95,"武昌起义成功","1911年10月10日武昌新军中的革命党人发动起义迅速占领了武汉三镇。随后全国多个省份纷纷宣布独立响应革命。清朝的统治土崩瓦解。","武昌起义改变了中国历史。"),
D("d2","我在美国得知消息太激动了！立即启程回国与同志们共商建国大计。","我","孙",88,"孙中山从海外回国","武昌起义爆发时孙中山正在美国丹佛市筹款。他得知消息后立即取道欧洲回国一路上与各国政府和媒体交涉争取国际社会对中国革命的支持。","孙中山回到祖国。"),
D("d3","各省代表齐聚南京推举我为临时大总统。这是全国人民的信任我深感责任重大。","我","孙",90,"孙中山当选临时大总统","1912年1月1日孙中山在南京就任中华民国临时大总统。中华民国正式成立结束了中国两千多年的封建帝制。","中华民国正式成立。"),
D("d4","中华民国临时政府成立后颁布了《中华民国临时约法》。这是中国历史上第一部资产阶级宪法。","我","孙",89,"临时约法","《中华民国临时约法》于1912年3月颁布是中国历史上第一部资产阶级性质的宪法文件。","中国第一部宪法诞生。"),
D("d5","为了让革命尽快成功我同意把总统之位让给袁世凯条件是他必须拥护共和遵守临时约法。","我","孙",82,"孙中山让位袁世凯","1912年2月在袁世凯表示拥护共和的条件下孙中山同意辞去临时大总统职务让位给袁世凯。","让位的决定引发争议。"),
D("d6","清帝退位了！两千年的帝制终于结束了！这一天中国人民等了太久太久。","我","孙",93,"清帝退位与帝制终结","1912年2月12日清帝溥仪正式退位标志着清朝灭亡和中国两千多年封建帝制的终结。","帝制终结共和开启。")]),
A("act-7","捍卫共和",False,"袁世凯篡夺了革命果实后逐步走向复辟帝制。你孙中山对此进行了坚决的斗争先后发动了'二次革命'和'护国运动'。",[N("陈独秀","袁世凯竟然要当皇帝！这是历史的倒退！我们必须反对！","陈"),N("梁启超","我也是曾经拥护袁世凯的但他要复辟帝制我也坚决反对！","梁")],[
D("d1","袁世凯复辟帝制这是对辛亥革命成果的公然背叛！我们必须发动护国运动捍卫共和！","我","孙",91,"护国运动","1915年12月袁世凯宣布恢复帝制。孙中山立即发动了护国运动联合蔡锷唐继尧等人在云南起义武装反对袁世凯称帝。在全国人民的强烈反对下袁世凯被迫取消帝制不久后病死。","护国运动捍卫了共和。"),
D("d2","辛亥革命的果实虽然被袁世凯窃取了但共和的理念已经深入人心。帝制已经不可能再回来了。","我","孙",87,"共和理念的深入人心","袁世凯复辟帝制的失败说明共和的理念已经深入人心任何企图恢复帝制的行为都注定失败。","共和理念不可逆转。"),
D("d3","陈独秀的新文化运动从思想文化层面继续推动中国的进步。","我","孙",83,"新文化运动的贡献","新文化运动（1915年开始）在思想文化层面继续推动中国的进步。陈独秀胡适鲁迅等人用白话文写作传播民主和科学思想。","新文化运动影响深远。"),
D("d4","二次革命虽然失败了但革命的力量没有被消灭。我们要重新组织准备新的斗争。","我","孙",80,"二次革命的教训","1913年孙中山发动'二次革命'武装讨伐袁世凯但由于力量薄弱而失败。","从失败中吸取教训。"),
D("d5","要实现真正的民主共和仅仅推翻皇帝是不够的。还必须建立完善的民主制度培养民主意识。","我","孙",85,"民主建设的长期性","推翻帝制只是革命的第一步。建立真正的民主共和制度需要长期的努力。","民主建设任重道远。"),
D("d6","路虽然漫长但方向是明确的。民主科学富强——这是中国必须走的路。","我","孙",86,"中国前进的方向","从洋务运动到戊戌变法从辛亥革命到新文化运动中国近代化的方向越来越明确。","方向明确信心坚定。")]),
A("act-8","新文化运动",True,"1915年陈独秀创办《新青年》杂志发起了新文化运动。提倡民主与科学反对封建旧文化。你孙中山虽然与陈独秀在方法上有所不同但都认识到思想启蒙对中国的重要性。",[N("陈独秀","民主和科学是推动社会进步的两个轮子。中国要富强必须拥抱这两样东西。","陈"),N("梁启超","新文化运动确实唤醒了青年人的思想。白话文让更多的人能够读书识字。","梁")],[
D("d1","陈独秀先生说'只有德先生和赛先生可以救治中国'。虽然我们是革命派但在追求民主和科学方面我们是一致的。","我","孙",88,"孙中山评价新文化运动","新文化运动是中国近代最重要的思想解放运动。陈独秀提出'德先生'（民主）和'赛先生'（科学）作为救国的两大旗帜与孙中山的三民主义在核心理念上是相通的。","新文化运动推动了思想解放。"),
D("d2","鲁迅先生的《狂人日记》用白话文写作揭露了封建礼教'吃人'的本质。","我","孙",85,"鲁迅与新文化运动","鲁迅的《狂人日记》（1918年）是中国第一篇白话文小说以犀利笔触揭露了封建礼教对人的压迫。","白话文运动影响深远。"),
D("d3","五四运动是青年人的运动。学生们走上街头高喊'外争国权内惩国贼'。这一刻中国青年觉醒了！","我","孙",90,"五四运动","1919年5月4日北京学生发动了五四运动抗议巴黎和会上中国外交的失败。五四运动标志着中国新民主主义革命的开端。","五四运动标志着新时代的开始。"),
D("d4","五四运动后马克思主义在中国广泛传播。李大钊陈独秀等人开始组建中国共产党。","我","孙",82,"马克思主义在中国的传播","五四运动后马克思主义在中国迅速传播。1921年陈独秀李大钊等人创建了中国共产党。","中国共产党的成立改变了中国的命运。"),
D("d5","新文化运动和五四运动的伟大意义在于它唤醒了一整代中国人。思想的觉醒比任何技术进步都重要。","我","孙",87,"思想觉醒的重要意义","新文化运动和五四运动的深远意义在于它从根本上改变了中国人的思想方式。民主科学平等等现代理念开始深入人心。","思想觉醒是最深刻的变革。"),
D("d6","从洋务运动到新文化运动从学习技术到变革思想中国近代化经历了一个不断深化的过程。","我","孙",86,"近代化的不断深化","中国近代化的历程可以概括为三个层面：技术层面（洋务运动）制度层面（戊戌变法辛亥革命）思想层面（新文化运动五四运动）。","近代化是一个系统工程。")]),
A("act-9","孙中山的遗产",False,"1925年3月12日你孙中山在北京病逝。临终前你留下了'革命尚未成功同志仍须努力'的遗训。你的一生虽然充满挫折但你的理想和精神影响了整个中国近代史。",[N("宋庆龄","先生您的三民主义和精神遗产我们会继续传承下去。","宋"),N("百姓","中山先生虽然走了但他的精神永远活在我们心中。","百")],[
D("d1","革命尚未成功同志仍须努力。这是我最后的遗言也是对全国人民的期望。","我","孙",96,"孙中山的临终遗言","孙中山于1925年3月12日在北京病逝享年59岁。他的临终遗言'革命尚未成功同志仍须努力'成为激励无数后来者的名言。","遗言激励了一代又一代中国人。"),
D("d2","我这一辈子从行医到革命走过了漫长的道路。虽然经历了无数次失败但我从来没有放弃过。","我","孙",88,"孙中山回顾一生","孙中山从一名医生转变为革命家一生致力于推翻帝制建立共和振兴中华。他经历了十多次起义失败多次被流放但始终没有放弃革命理想。","孙中山的一生是奋斗的一生。"),
D("d3","三民主义——民族民权民生。这是我为中国设计的一套完整的建国方案。","我","孙",90,"三民主义的完整阐述","三民主义是中国近代最重要的政治理论之一。民族主义主张各民族平等国家统一；民权主义主张民主共和；民生主义主张平均地权发展经济改善民生。","三民主义影响深远。"),
D("d4","我希望我的同志们能够继续为振兴中华而奋斗。不管走什么路只要目标是让中国强大起来就是好的。","我","孙",85,"孙中山对同志的期望","孙中山在遗嘱中表达了对革命同志的期望和信任。","孙中山的期望指引着后来的路。"),
D("d5","我对中国未来的发展有一些建议写在了《建国方略》中。希望后人能够参考。","我","孙",83,"建国方略的规划","孙中山的《建国方略》是一部宏大的国家建设规划包括铁路公路港口水利等基础设施建设以及农业工业商业的发展蓝图。","建国方略展现了远见。"),
D("d6","如果后人能够沿着正确的道路走下去中国的未来一定会光明。我对这一点深信不疑。","我","孙",87,"孙中山对中国未来的信心","孙中山对中国未来的信心正在被现实不断验证。","孙中山的预言正在实现。")]),
A("act-10","历史的启示",False,"从洋务运动到辛亥革命从戊戌变法到新文化运动中国近代化的探索历程虽然充满曲折但方向始终是明确的——追求富强追求民主追求进步。",[N("梁启超","从器物到制度再到思想中国近代化的三步曲每一步都走得很艰难但每一步都不可或缺。","梁"),N("陈独秀","新文化运动和五四运动是思想层面的革命。只有思想解放了中国才能真正进步。","陈")],[
D("d1","中国近代史告诉我们：封闭就要落后落后就要挨打。只有开放和学习才能实现国家的富强。","我","孙",90,"开放学习的重要性","中国近代史最深刻的教训就是封闭保守的危害。改革开放以来中国的快速发展也证明了开放和学习是实现国家富强的重要途径。","开放是强国之路。"),
D("d2","技术进步重要但制度变革和思想解放更加重要。三者缺一不可。","我","孙",88,"全面近代化的必要性","中国近代化的历程证明单纯的技术进步或制度变革或思想解放都不足以实现国家的全面振兴。必须三者并进。","全面改革是必要的。"),
D("d3","每个时代都有自己的使命。我们那代人的使命是推翻帝制后人的使命是建设强国。","我","孙",86,"不同时代的历史使命","每一代中国人都有自己的历史使命。使命虽然不同但目标一致——让中国强大让人民幸福。","使命代代相传。"),
D("d4","团结是战胜一切困难的最有力武器。近代中国之所以屡遭挫折一个重要原因就是不团结。","我","孙",85,"团结的重要性","近代中国屡遭外来侵略的一个重要原因就是内部不团结。辛亥革命的成功在一定程度上得益于革命力量的大团结。","团结就是力量。"),
D("d5","历史的教训不能忘记但也不能沉溺于仇恨。铭记历史是为了更好地走向未来。","我","孙",82,"铭记历史面向未来","孙中山主张理性对待历史。铭记近代屈辱的历史教训但不要沉溺于仇恨。","以史为鉴面向未来。"),
D("d6","我对中国充满信心。这片土地上有五千年文明的底蕴有亿万人勤劳智慧的人民。中国的未来一定会更加光明。","我","孙",91,"孙中山对中国的信心","孙中山对中国的信心正在被现实不断验证。今天的中国已经成为世界第二大经济体。","中国的未来充满光明。")]),
A("act-11","探索的启示",True,"中国近代化的探索虽然曲折但每一步都不是白走的。洋务运动积累了工业基础戊戌变法播下了改革种子辛亥革命推翻了帝制新文化运动唤醒了思想。这些探索共同构成了中国走向现代化的完整路径。",[N("曾国藩","虽然洋务运动最终失败了但我们创办的工厂和学校为后来的发展打下了一定的基础。","曾"),N("陈独秀","新文化运动和五四运动的贡献不在于它改变了什么而在于它唤醒了什么。","陈")],[
D("d1","每一种探索都有它的价值和局限。洋务运动的局限是只学技术不改制度。","我","孙",90,"各种探索的价值和局限","中国近代各种救国探索都有其价值和局限。这些经验教训为后来的革命提供了重要参考。","每一步探索都有价值。"),
D("d2","改良与革命的争论持续了很久。历史最终证明在专制体制下革命是唯一的出路。","我","孙",87,"革命与改良的历史结论","从戊戌变法的失败到辛亥革命的成功历史证明了在中国当时的条件下改良主义的道路走不通。","革命是历史的必然选择。"),
D("d3","从器物到制度再到思想近代化的三个层面必须协调推进缺一不可。","我","孙",88,"近代化三层面","洋务运动（器物层面）、戊戌变法和辛亥革命（制度层面）、新文化运动和五四运动（思想层面）——中国近代化经历了从浅到深的三个层面。","近代化是一个系统工程。"),
D("d4","新文化运动最大的贡献是唤醒了青年一代的思想。青年的觉醒是民族复兴的基础。","我","孙",86,"青年觉醒的重要性","新文化运动和五四运动的最大贡献是唤醒了一整代中国青年的思想。","青年是国家的未来。"),
D("d5","每一种探索都为中国积累了经验。这些经验最终汇聚成了中国走向现代化的正确道路。","我","孙",83,"经验积累的价值","中国近代化的每一次探索都为中国积累了宝贵的经验。","失败是成功的基石。"),
D("d6","孙中山先生的三民主义思想虽然是在特定历史条件下提出的但其核心精神至今仍有重要的参考价值。","我","孙",85,"三民主义的当代价值","三民主义的核心精神在今天仍然具有重要的参考价值：维护国家统一和民族团结、推进民主政治建设、改善人民生活。","三民主义精神永不过时。")]),
A("act-12","尾声",False,"从洋务运动到新文化运动中国近代化探索经历了半个多世纪的曲折历程。你孙中山虽然只走完了其中的一段路但你相信中华民族一定能找到正确的道路实现伟大复兴。",[N("孙中山","革命尚未成功同志仍须努力。","孙"),N("百姓","中山先生的精神永远激励着我们。中国一定会强大起来的。","百")],[
D("d1","从鸦片战争到辛亥革命从帝制到共和中国走过了最艰难的一段路。但最艰难的路已经走过了。","我","孙",90,"近代史的艰辛","从1840年鸦片战争到1912年中华民国成立中国经历了70多年的屈辱和抗争。这段历史虽然充满了苦难但也锻炼了中华民族的意志和韧性。","最艰难的路已经走过了。"),
D("d2","我孙中山虽然不是完美的但我为国家和民族倾注了一生的精力。这一点我问心无愧。","我","孙",88,"孙中山的自我评价","孙中山一生致力于革命事业经历了无数挫折和失败但始终没有放弃。","孙中山问心无愧。"),
D("d3","近代化的探索告诉我们没有哪条路是平坦的但只要方向正确坚持不懈就一定能到达目的地。","我","孙",87,"坚持正确方向","中国近代化的探索充满了曲折和挫折但前进的方向始终是明确的——追求富强追求民主追求进步。","方向正确坚持不懈。"),
D("d4","中国的未来属于青年一代。希望他们能比我们做得更好让中国真正成为世界的强国。","我","孙",85,"对年轻一代的期望","孙中山对青年一代的期望在今天正在实现。","年轻一代不负期望。"),
D("d5","从林则徐的虎门销烟到今天的民族复兴中华民族走过了漫长而辉煌的道路。","我","孙",89,"中华民族的光辉历程","从1840年林则徐虎门销烟到21世纪的民族复兴中华民族走过了从屈辱到觉醒从苦难到复兴的伟大历程。","民族的历程光辉灿烂。"),
D("d6","中国一定会强大。对此我深信不疑。","我","孙",93,"孙中山的坚定信念","孙中山对中国未来的坚定信念正在被现实不断验证。中华民族伟大复兴的中国梦正在逐步实现。","中国的未来光明灿烂。")])
]});

